long long dist(long long a, long long b) {
    return std::llabs(a - b);
}

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    std::cin >> n;
    std::vector<long long> a(n + 2, 0);
    for (int i = 1; i <= n; ++i) std::cin >> a[i];
    long long total = 0;
    for (int i = 0; i + 1 <= n + 1; ++i) total += dist(a[i], a[i + 1]);
    for (int i = 1; i <= n; ++i) {
        long long ans = total - dist(a[i - 1], a[i]) - dist(a[i], a[i + 1]) + dist(a[i - 1], a[i + 1]);
        std::cout << ans << '\n';
    }
    return 0;
}

