#include <iostream>

long long count_pairs(long long n, long long s) {
    if (s < 2 || s > 2 * n) return 0;
    if (s <= n + 1) return s - 1;
    return 2 * n - s + 1;
}

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    long long n, k;
    std::cin >> n >> k;
    long long ans = 0;
    for (long long s = 2; s <= 2 * n; ++s) {
        ans += count_pairs(n, s) * count_pairs(n, s - k);
    }
    std::cout << ans << '\n';
    return 0;
}

