#include <iostream>

long long mod_pow(long long a, long long e, long long mod) {
    long long res = 1 % mod;
    a %= mod;
    while (e > 0) {
        if (e & 1) res = res * a % mod;
        a = a * a % mod;
        e >>= 1;
    }
    return res;
}

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    long long a, b, c;
    std::cin >> a >> b >> c;
    int last = static_cast<int>(a % 10);
    int cycle = 1;
    if (last == 2 || last == 3 || last == 7 || last == 8) cycle = 4;
    else if (last == 4 || last == 9) cycle = 2;
    long long e = mod_pow(b, c, cycle);
    if (e == 0) e = cycle;
    int ans = 1;
    for (int i = 0; i < e; ++i) ans = ans * last % 10;
    std::cout << ans << '\n';
    return 0;
}

