#include <iostream>

long long priced_count(long long x, long long rate) {
    // 最大 A 满足 floor(A*rate/100) <= x。
    return (100 * (x + 1) - 1) / rate;
}

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    long long t, n;
    std::cin >> t >> n;
    long long rate = 100 + t;
    long long low = 0, high = (1LL << 62);
    while (high - low > 1) {
        long long mid = (low + high) / 2;
        long long missing = mid - priced_count(mid, rate);
        if (missing >= n) high = mid;
        else low = mid;
    }
    std::cout << high << '\n';
    return 0;
}

#include <algorithm>
#include <cstdlib>
#include <iostream>
#include <vector>

struct Point {
    long long x, y;
    int id;
};

long long dist(const Point& a, const Point& b) {
    return std::max(std::llabs(a.x - b.x), std::llabs(a.y - b.y));
}

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    std::cin >> n;
    std::vector<Point> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i].x >> p[i].y;
        p[i].id = i;
    }
    std::vector<int> cand;
    auto add_extreme = [&](auto comp) {
        std::vector<Point> q = p;
        std::sort(q.begin(), q.end(), comp);
        for (int i = 0; i < std::min(n, 4); ++i) cand.push_back(q[i].id);
        for (int i = std::max(0, n - 4); i < n; ++i) cand.push_back(q[i].id);
    };
    add_extreme([](const Point& a, const Point& b) { return a.x < b.x; });
    add_extreme([](const Point& a, const Point& b) { return a.y < b.y; });
    std::sort(cand.begin(), cand.end());
    cand.erase(std::unique(cand.begin(), cand.end()), cand.end());

    std::vector<long long> ds;
    for (std::size_t i = 0; i < cand.size(); ++i) {
        for (std::size_t j = i + 1; j < cand.size(); ++j) ds.push_back(dist(p[cand[i]], p[cand[j]]));
    }
    std::sort(ds.begin(), ds.end(), std::greater<long long>());
    std::cout << ds[1] << '\n';
    return 0;
}

