#include <iostream>
#include <vector>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    const long long MOD = 998244353LL;
    int n, k;
    std::cin >> n >> k;
    std::vector<char> type(k + 1);
    std::vector<int> pos(k + 1), fixed(n + 1, 0);
    for (int i = 1; i <= k; ++i) {
        std::cin >> type[i] >> pos[i];
        fixed[pos[i]] = i;
    }

    long long ans = 1;
    for (int i = 1; i <= n; ++i) {
        if (fixed[i]) continue;
        int choices = 0;
        for (int x = 1; x <= k; ++x) {
            if (type[x] == 'L' && pos[x] < i) ++choices;
            if (type[x] == 'R' && pos[x] > i) ++choices;
        }
        ans = ans * choices % MOD;
    }
    std::cout << ans << '\n';
    return 0;
}
